import{_ as a,o as i,c as t,a2 as r}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"Archiving","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/archiving.md","filePath":"en/guide/archiving.md"}'),n={name:"en/guide/archiving.md"};function s(o,e,l,h,c,d){return i(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="archiving" tabindex="-1">Archiving <a class="header-anchor" href="#archiving" aria-label="Permalink to &quot;Archiving&quot;">​</a></h1><p>Nid allows you to save your emails to your NAS in <strong>EML</strong> format (one file per email). Archives are indexed in PostgreSQL for fast searching.</p><hr><h2 id="why-archive" tabindex="-1">Why archive? <a class="header-anchor" href="#why-archive" aria-label="Permalink to &quot;Why archive?&quot;">​</a></h2><ul><li><strong>Free up your Gmail quota</strong>: delete emails from Gmail after archiving them locally</li><li><strong>Long-term backup</strong>: EML files are in a standard format, readable by any email client (Thunderbird, Outlook, etc.)</li><li><strong>Fast search</strong>: archives are full-text indexed in PostgreSQL</li><li><strong>Your data stays with you</strong>: no data leaves your network</li></ul><hr><h2 id="archiving-emails" tabindex="-1">Archiving emails <a class="header-anchor" href="#archiving-emails" aria-label="Permalink to &quot;Archiving emails&quot;">​</a></h2><h3 id="archiving-by-selection" tabindex="-1">Archiving by selection <a class="header-anchor" href="#archiving-by-selection" aria-label="Permalink to &quot;Archiving by selection&quot;">​</a></h3><ol><li>In <strong>My emails</strong>, select the emails to archive</li><li>Click <strong>Archive to NAS</strong> in the action bar</li><li>An archiving job is created with real-time tracking</li></ol><h3 id="archiving-by-query-archive-all" tabindex="-1">Archiving by query (archive all) <a class="header-anchor" href="#archiving-by-query-archive-all" aria-label="Permalink to &quot;Archiving by query (archive all)&quot;">​</a></h3><ol><li>In <strong>My emails</strong>, enter a search query (e.g. <code>from:amazon.fr older_than:6m</code>)</li><li>Click <strong>Archive all</strong></li><li>All matching emails are archived differentially</li></ol><h3 id="differential-archiving" tabindex="-1">Differential archiving <a class="header-anchor" href="#differential-archiving" aria-label="Permalink to &quot;Differential archiving&quot;">​</a></h3><p>Archiving is <strong>differential</strong> by default: only emails that have not yet been archived are processed. If you archive the same query twice, the second run only processes new emails.</p><blockquote><p>📸 <em>Suggested screenshot: &quot;Archive all&quot; button on the My emails page</em></p></blockquote><hr><h2 id="browsing-archives" tabindex="-1">Browsing archives <a class="header-anchor" href="#browsing-archives" aria-label="Permalink to &quot;Browsing archives&quot;">​</a></h2><p>The <strong>Archives</strong> page in the sidebar displays all your archived emails.</p><h3 id="full-text-search" tabindex="-1">Full-text search <a class="header-anchor" href="#full-text-search" aria-label="Permalink to &quot;Full-text search&quot;">​</a></h3><p>The search bar enables <strong>full-text search</strong> across your archives. The search covers:</p><ul><li><strong>Email subject</strong> (highest priority)</li><li><strong>Sender</strong> (medium priority)</li><li><strong>Content</strong> of the email (excerpt/snippet, lowest priority)</li></ul><blockquote><p>📸 <em>Suggested screenshot: Archives page with the full-text search bar and results</em></p></blockquote><h3 id="sorting-and-filters" tabindex="-1">Sorting and filters <a class="header-anchor" href="#sorting-and-filters" aria-label="Permalink to &quot;Sorting and filters&quot;">​</a></h3><p>You can sort archives by:</p><ul><li>Date (newest / oldest)</li><li>Size (largest / smallest)</li><li>Sender</li></ul><h3 id="reading-an-archived-email" tabindex="-1">Reading an archived email <a class="header-anchor" href="#reading-an-archived-email" aria-label="Permalink to &quot;Reading an archived email&quot;">​</a></h3><p>Click on an archived email to open it in the built-in reader. The content is read directly from the EML file on disk.</p><p>If the email is <strong>encrypted</strong>, it will be decrypted on the fly (you must have configured your passphrase — see <a href="./privacy.html#chiffrement-des-archives">Privacy</a>).</p><h3 id="conversation-thread-view" tabindex="-1">Conversation (thread) view <a class="header-anchor" href="#conversation-thread-view" aria-label="Permalink to &quot;Conversation (thread) view&quot;">​</a></h3><p>Archives support the <strong>conversation</strong> view: emails sharing the same thread are grouped together. Switch between list view and conversation view with the toggle at the top of the page.</p><blockquote><p>📸 <em>Suggested screenshot: list/conversation toggle on the Archives page</em></p></blockquote><hr><h2 id="archived-attachments" tabindex="-1">Archived attachments <a class="header-anchor" href="#archived-attachments" aria-label="Permalink to &quot;Archived attachments&quot;">​</a></h2><p>Attachments are extracted and stored separately during archiving. You can download them individually from:</p><ul><li>The archived email reader</li><li>The <strong>Attachments</strong> page (Archives tab)</li></ul><hr><h2 id="zip-export" tabindex="-1">ZIP export <a class="header-anchor" href="#zip-export" aria-label="Permalink to &quot;ZIP export&quot;">​</a></h2><p>Export a selection of archived emails in ZIP format:</p><ol><li>In <strong>Archives</strong>, select the emails to export</li><li>Click <strong>Export as ZIP</strong></li><li>A ZIP file containing the EML files is downloaded</li></ol><hr><h2 id="disk-organization" tabindex="-1">Disk organization <a class="header-anchor" href="#disk-organization" aria-label="Permalink to &quot;Disk organization&quot;">​</a></h2><p>Archives are organized on the NAS according to the following structure:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/archives/</span></span>
<span class="line"><span>└── {account_id}/</span></span>
<span class="line"><span>    └── {year}/</span></span>
<span class="line"><span>        └── {month}/</span></span>
<span class="line"><span>            ├── {message_id}.eml</span></span>
<span class="line"><span>            └── attachments/</span></span>
<span class="line"><span>                ├── invoice.pdf</span></span>
<span class="line"><span>                └── photo.jpg</span></span></code></pre></div><p>Each email is identified by a unique UUID (the <code>gmail_message_id</code>).</p><hr><h2 id="archive-trash" tabindex="-1">Archive trash <a class="header-anchor" href="#archive-trash" aria-label="Permalink to &quot;Archive trash&quot;">​</a></h2><p>Archived emails can be deleted via the <strong>trash</strong>. Deletion is a <strong>soft-delete</strong>: emails are not immediately erased from disk.</p><h3 id="deleting-archives" tabindex="-1">Deleting archives <a class="header-anchor" href="#deleting-archives" aria-label="Permalink to &quot;Deleting archives&quot;">​</a></h3><ol><li>In <strong>Archives</strong>, select the emails to delete</li><li>Click <strong>Delete</strong> in the action bar</li><li>Confirm the deletion — emails are moved to trash</li></ol><blockquote><p>📸 <em>Suggested screenshot: Delete button and confirmation in the archive action bar</em></p></blockquote><h3 id="browsing-the-trash" tabindex="-1">Browsing the trash <a class="header-anchor" href="#browsing-the-trash" aria-label="Permalink to &quot;Browsing the trash&quot;">​</a></h3><p>Switch to the <strong>Trash</strong> tab (next to List and Conversations) to see deleted emails:</p><ul><li>Each email shows its <strong>deletion date</strong> and the <strong>time remaining</strong> before permanent purge</li><li>A color indicator highlights emails close to expiration (red ≤ 3 days, orange ≤ 7 days)</li></ul><blockquote><p>📸 <em>Suggested screenshot: Trash tab with expiration indicators</em></p></blockquote><h3 id="restoring-emails" tabindex="-1">Restoring emails <a class="header-anchor" href="#restoring-emails" aria-label="Permalink to &quot;Restoring emails&quot;">​</a></h3><ol><li>In the <strong>Trash</strong> tab, select the emails to restore</li><li>Click <strong>Restore</strong> in the action bar</li><li>Emails are returned to the archives</li></ol><p>You can also restore an individual email by clicking the restore icon in its row.</p><h3 id="emptying-the-trash" tabindex="-1">Emptying the trash <a class="header-anchor" href="#emptying-the-trash" aria-label="Permalink to &quot;Emptying the trash&quot;">​</a></h3><p>The <strong>Empty trash</strong> button <strong>permanently</strong> deletes all emails in the trash:</p><ul><li>EML files are deleted from disk</li><li>Associated attachments are deleted</li><li>Database records are removed</li><li><strong>This action is irreversible</strong></li></ul><h3 id="automatic-purge" tabindex="-1">Automatic purge <a class="header-anchor" href="#automatic-purge" aria-label="Permalink to &quot;Automatic purge&quot;">​</a></h3><p>A scheduled job automatically purges emails that have been in the trash for more than <strong>30 days</strong> (by default). This job runs daily at 4 AM.</p><p>You can configure the purge from the <strong>Jobs</strong> page:</p><ul><li><strong>Enable/disable</strong> automatic purge</li><li><strong>Change the retention period</strong> (1 to 365 days)</li></ul><blockquote><p>📸 <em>Suggested screenshot: trash configuration section on the Jobs page</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Advice</p><p>If you accidentally delete important emails, you can restore them as long as they haven&#39;t been purged. Check the trash regularly to avoid surprises.</p></div>`,65)])])}const u=a(n,[["render",s]]);export{p as __pageData,u as default};
